const results = $('Get keyword ideas from Google Keyword Planner').first().json.results;

function microsToUSD(micros) {
  if (!micros) return null;
  return "$" + (parseInt(micros) / 1_000_000).toFixed(2);
}

return results.map(item => {
  const metrics = item.keywordIdeaMetrics || {};
  return {
    json: {
      keyword: item.text,
      avgMonthlySearches: metrics.avgMonthlySearches || "0",
      competition: metrics.competition || "UNSPECIFIED",
      competitionIndex: metrics.competitionIndex || "0",
      lowTopOfPageBid: microsToUSD(metrics.lowTopOfPageBidMicros),
      highTopOfPageBid: microsToUSD(metrics.highTopOfPageBidMicros)
    }
  };
});

const input = $input.first().json;

// Helper: čisti string od leading/trailing spaces
function clean(str) {
  return (str || '').trim();
}

// Helper: normalizuje separator - radi sa zarezom, tačka-zarezom, | i višestrukim razmacima
function parseList(str) {
  return (str || '')
    .replace(/[;|\\/]/g, ',')
    .split(',')
    .map(item => item.trim())
    .filter(item => item.length > 0);
}

const websiteUrl = clean(input['Website URL']);
const companyName = clean(input['Company name']);
const industry = clean(input['Industry']);
const productsRaw = clean(input['Products/Services']);
const notes = clean(input['Notes']);

const seedKeywords = parseList(input['Seed keywords']);

return [{
  json: {
    ...input,
    'Website URL': websiteUrl,
    'Company name': companyName,
    'Industry': industry,
    'Products/Services': productsRaw,
    'Notes': notes,
    seedKeywords,
    productsFormatted: productsRaw
  }
}];
